const moduleUrls = new Map();

function resolveEmbeddedModule(specifier, referrer) {
    if (!specifier.startsWith('.')) return specifier;

    const parts = referrer.split('/');
    parts.pop();

    for (const part of specifier.split('/')) {
        if (!part || part === '.') continue;
        if (part === '..') parts.pop();
        else parts.push(part);
    }

    return parts.join('/');
}

function rewriteEmbeddedImports(source, referrer) {
    return source
        .replace(/\bfrom\s*(["'])(\.[^"']+)\1/g, (_match, _quote, specifier) => {
            const target = resolveEmbeddedModule(specifier, referrer);
            return 'from ' + JSON.stringify(getEmbeddedModuleUrl(target));
        })
        .replace(/\bimport\s*(["'])(\.[^"']+)\1/g, (_match, _quote, specifier) => {
            const target = resolveEmbeddedModule(specifier, referrer);
            return 'import ' + JSON.stringify(getEmbeddedModuleUrl(target));
        });
}

function getEmbeddedModuleUrl(path) {
    const existing = moduleUrls.get(path);
    if (existing) return existing;

    const source = embeddedModules.get(path);
    if (source === undefined) {
        throw new Error('Missing embedded Material module: ' + path);
    }

    const rewritten = rewriteEmbeddedImports(source, path);
    const url = URL.createObjectURL(new Blob([rewritten], { type: 'text/javascript' }));
    moduleUrls.set(path, url);
    return url;
}

